sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

	// get values off of the form to use to retrieve names
	var formValues = {};
	formValues.assigned_to = {id:g_form.getValue('u_assigned_member'), name:'' };
	formValues.u_internal_contact = {id:g_form.getValue('u_internal_contact'), name:'' };
	formValues.poc_name = {id:g_form.getValue('poc_name'), name:'' };
	formValues.u_subtask_assigned_member_s = {ids:g_form.getValue('u_subtask_assigned_member_s'), names:'', arrIds: g_form.getValue('u_subtask_assigned_member_s').split(','), arrNames:[], arrKeepIds:[] };
	formValues.tasking_authority = {id:g_form.getValue('u_tasking_authority'), abbr:'' };
	formValues.primary_office = {id:g_form.getValue('u_primary_office'), abbr:'' };
	formValues.primary_assignee = {id:g_form.getValue('u_primary_assignee'), abbr:'' };	
	formValues.u_subtask_primary_assignee_s = {ids:g_form.getValue('u_subtask_primary_assignee_s'), abbrs:'', arrIds: g_form.getValue('u_subtask_primary_assignee_s').split(','), arrAbbrs:[], arrKeepIds:[] };
	formValues.u_external_ou = {id:g_form.getValue('u_external_ou'), abbr:'' };

	var formLabels = {};
	formLabels.assigned_to = g_form.getLabelOf('u_assigned_member');
	formLabels.u_internal_contact = g_form.getLabelOf('u_internal_contact');
	formLabels.poc_name = g_form.getLabelOf('poc_name');
	formLabels.u_subtask_assigned_member_s = g_form.getLabelOf('u_subtask_assigned_member_s');
	formLabels.tasking_authority = g_form.getLabelOf('u_tasking_authority');
	formLabels.primary_office = g_form.getLabelOf('u_primary_office');
	formLabels.primary_assignee = g_form.getLabelOf('u_primary_assignee');
	formLabels.u_subtask_primary_assignee_s = g_form.getLabelOf('u_subtask_primary_assignee_s');	
	formLabels.u_external_ou = g_form.getLabelOf('u_external_ou');	
	formLabels.UI_Type = typeof spModal != 'undefined' ? 'Portal' : 'Platform';

	// Get the OUs and Members allowed for the restricted group
	var taskInfo  = new GlideAjax('ClientTaskInfo');
	taskInfo.addParam('sysparm_name','getMembersAndOUsForRestrictedGroup');
	taskInfo.addParam("newRestrictedGroupId", newValue);
	taskInfo.addParam("previousRestrictedGroupId", oldValue);
	taskInfo.addParam("formValues", JSON.stringify(formValues));
	taskInfo.addParam("formLabels", JSON.stringify(formLabels));
	// call script include to determine if this user is a tasking authority of the primary assignee OU.
	taskInfo.getXML(f_returnGetMembersAndOUsForRestrictedGroup);
}

function f_returnGetMembersAndOUsForRestrictedGroup(response)
{
	var answer = response.responseXML.documentElement.getAttribute("answer");
	// if the current user is a Tasking Authority in the OU, allow them to change the assigned members
	var restrictedOUsandMembers = JSON.parse(answer);

	var msg = restrictedOUsandMembers.restrictedGroupMessage;
	var clear_fields = restrictedOUsandMembers.clear_fields;

	// only get confirmation if a field violates the restricted group
	if(clear_fields.tasking_authority
	   || clear_fields.primary_office
	   || clear_fields.primary_assignee
	   || clear_fields.u_subtask_primary_assignee_s
	   || clear_fields.u_external_ou
	   || clear_fields.u_reviewer
	   || clear_fields.assigned_to
	   || clear_fields.on_behalf_of
	   || clear_fields.poc_name
	   || clear_fields.u_internal_contact	   
	   || clear_fields.u_subtask_assigned_member_s	   
	  ){
		var ConfirmOrNot = false;
		if (typeof spModal != 'undefined') {
			spModal.confirm(msg).then(function(confirmed){
				f_confirmationAnswer(confirmed, restrictedOUsandMembers);
			}, function(confirmed) {
				f_confirmationAnswer(confirmed, restrictedOUsandMembers);
			});
		} else {
			var gm = new GlideModal('UI_dialog_name');
			//Sets the dialog title
			// no easy way to put a button on this without building a page just for confirmation
			// we probably should add a page just for confirmation in the future, but for now it will be faster to just stay with confrim
			//gm.setTitle('Show title'); 
			//gm.setPreference('name', 'value');
			//gm.setWidth(550);
			//Opens the dialog
			//gm.render(); 
			//gm.renderWithContent(msg);

			ConfirmOrNot=confirm(msg);
			f_confirmationAnswer(ConfirmOrNot, restrictedOUsandMembers);
		}

	}
}

function f_confirmationAnswer(confrim, restrictedOUsandMembers) {
	var clear_fields = restrictedOUsandMembers.clear_fields;
	var previousRestrictedGroupId = restrictedOUsandMembers.previousRestrictedGroupId;
	var keepMemIds = restrictedOUsandMembers.returnFormValues.u_subtask_assigned_member_s.arrKeepIds.join(',');
	var keepOUIds = restrictedOUsandMembers.returnFormValues.u_subtask_primary_assignee_s.arrKeepIds.join(',');

	if (confrim==true) {
		// clear OUs and members not in the restricted group
		if(clear_fields.tasking_authority) g_form.clearValue('u_tasking_authority');
		if(clear_fields.primary_office) g_form.clearValue('u_primary_office');
		if(clear_fields.primary_assignee) g_form.clearValue('u_primary_assignee');
		if(clear_fields.u_subtask_primary_assignee_s) g_form.setValue('u_subtask_primary_assignee_s', keepOUIds);
		if(clear_fields.u_external_ou) g_form.clearValue('u_external_ou');
		if(clear_fields.assigned_to) g_form.clearValue('u_assigned_member');
		if(clear_fields.u_internal_contact) g_form.clearValue('u_internal_contact');
		if(clear_fields.poc_name) g_form.clearValue('poc_name');
		if(clear_fields.u_subtask_assigned_member_s) g_form.setValue('u_subtask_assigned_member_s', keepMemIds);
	} else {
		g_form.setValue('u_restricted_group', previousRestrictedGroupId);
	}
}
